html:
{%- set settings = frappe.get_cached_doc('Hamilton Settings') -%}
{%- set company = frappe.get_cached_doc('Company', doc.company) -%}
{%- set venue_name = company.company_name or doc.company -%}
{%- set gst_hst_number = settings.gst_hst_registration_number or '' -%}
{%- set is_cash = doc.payments and doc.payments[0].mode_of_payment == 'Cash' -%}
{%- set amount_paid = (doc.rounded_total or doc.grand_total) -%}
{%- set change_given = (doc.change_amount or 0) -%}
{%- set hst_row = (doc.taxes or [{}])[0] if (doc.taxes or []) else None -%}
<div class="hamilton-cash-receipt" style="font-family: monospace; font-size: 11pt; width: 280px; line-height: 1.3;">
  <div style="text-align: center; font-weight: bold; font-size: 13pt;">{{ venue_name }}</div>
  <div style="text-align: center;">GST/HST: {{ gst_hst_number }}</div>
  <div style="text-align: center;">{{ frappe.utils.format_datetime(doc.modified, 'yyyy-MM-dd HH:mm:ss') }}</div>
  <div style="text-align: center;">Receipt #: {{ doc.name }}</div>
  {%- if doc.has_admission_item and doc.has_admission_item() -%}
    {%- set session_no = (doc.items[0].get('hamilton_session') if doc.items else '') -%}
    {%- if session_no -%}
      <div style="text-align: center;">Session: {{ session_no }}</div>
    {%- endif -%}
  {%- endif -%}
  <div style="border-top: 1px dashed #000; margin: 4px 0;"></div>
  {%- for item in doc.items -%}
    <div>{{ item.item_name or item.item_code }}</div>
    <div style="display: flex; justify-content: space-between;">
      <span>&nbsp;&nbsp;{{ '{:g}'.format(item.qty) }} x ${{ '{:.2f}'.format(item.rate) }}</span>
      <span>${{ '{:.2f}'.format(item.amount) }}</span>
    </div>
  {%- endfor -%}
  <div style="border-top: 1px dashed #000; margin: 4px 0;"></div>
  <div style="display: flex; justify-content: space-between;">
    <span>Subtotal</span><span>${{ '{:.2f}'.format(doc.net_total) }}</span>
  </div>
  {%- if hst_row -%}
    <div style="display: flex; justify-content: space-between;">
      <span>HST {{ '{:g}'.format(hst_row.rate) }}%</span><span>${{ '{:.2f}'.format(hst_row.tax_amount) }}</span>
    </div>
  {%- endif -%}
  <div style="display: flex; justify-content: space-between; font-weight: bold;">
    <span>Grand Total</span><span>${{ '{:.2f}'.format(doc.grand_total) }}</span>
  </div>
  {%- if doc.rounded_total and doc.rounded_total != doc.grand_total -%}
    <div style="display: flex; justify-content: space-between;">
      <span>Rounded Total</span><span>${{ '{:.2f}'.format(doc.rounded_total) }}</span>
    </div>
  {%- endif -%}
  <div style="display: flex; justify-content: space-between;">
    <span>Amount Paid</span><span>${{ '{:.2f}'.format(amount_paid) }}</span>
  </div>
  {%- if is_cash -%}
    <div style="display: flex; justify-content: space-between;">
      <span>Change</span><span>${{ '{:.2f}'.format(change_given) }}</span>
    </div>
  {%- endif -%}
  <div style="border-top: 1px dashed #000; margin: 4px 0;"></div>
  <div style="text-align: center;">PAID -- {{ (doc.payments[0].mode_of_payment if doc.payments else 'CASH')|upper }}</div>
  <div style="text-align: center; margin-top: 4px;">Thank you</div>
</div>
